class Solution { public: bool solve(string s) { int i = 0, j = s.size() - 1; while (i < j) { if (s[i] != s[j]) return false; i++; j--; } return true; } };
class Main { public:
    int main() {
        string s; cin >> s;
        Solution solution;
        cout << (solution.solve(s) ? "Yes" : "No") << endl;
        return 0;
    };
};
int main() { return Main::main(); }
